sparql_query:
PREFIX goo:        <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:       <http://example.org/resource#>
PREFIX geosparql: <http://www.opengis.net/ont/geosparql#>
PREFIX geof:       <http://www.opengis.net/def/function/geosparql/>
PREFIX units:      <http://www.opengis.net/def/uom/OGC/1.0/>
PREFIX xsd:        <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:        <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:       <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?eventCount ?event ?efScale ?injuriesDirect
WHERE {
  {
    SELECT (COUNT(DISTINCT ?event) AS ?eventCount)
    WHERE {
      gokg:ClevelandCountyOK geosparql:hasGeometry ?countyGeom .
      ?countyGeom geosparql:asWKT ?countyWKT .
      ?event a goo:TornadoEventRecord ;
             goo:eventStartTime ?start ;
             goo:eventEndTime ?end ;
             goo:torFScale ?efScale ;
             goo:injuriesDirect ?injuriesDirect ;
             goo:lat ?eventLat ;
             goo:lon ?eventLon .
      BIND(STRDT(CONCAT("POINT(", STR(?eventLon), " ", STR(?eventLat), ")"), geosparql:wktLiteral) AS ?eventPoint)
      FILTER (?start < "2013-05-22T00:00:00"^^xsd:dateTime && ?end >= "2013-05-19T00:00:00"^^xsd:dateTime)
      FILTER (geof:distance(?eventPoint, ?countyWKT, units:metre) <= 10000)
    }
  }
  gokg:ClevelandCountyOK geosparql:hasGeometry ?countyGeom .
  ?countyGeom geosparql:asWKT ?countyWKT .
  ?event a goo:TornadoEventRecord ;
         goo:eventStartTime ?start ;
         goo:eventEndTime ?end ;
         goo:torFScale ?efScale ;
         goo:injuriesDirect ?injuriesDirect ;
         goo:lat ?eventLat ;
         goo:lon ?eventLon .
  BIND(STRDT(CONCAT("POINT(", STR(?eventLon), " ", STR(?eventLat), ")"), geosparql:wktLiteral) AS ?eventPoint)
  FILTER (?start < "2013-05-22T00:00:00"^^xsd:dateTime && ?end >= "2013-05-19T00:00:00"^^xsd:dateTime)
  FILTER (geof:distance(?eventPoint, ?countyWKT, units:metre) <= 10000)
}
ORDER BY ?event
